export const lessonEntities: ScheduledLessonDto[] = mockScheduledLessons;

type LessonDifficulty = 'easy' | 'medium' | 'hard';
type LessonLevel = 'A1' | 'A2' | 'B1' | 'B2' | 'C1' | 'C2';

export type MockLesson = {
  id: string;
  title: string;
  type: ScheduledLessonDto['type'];
  level: LessonLevel;
  duration: number;
  xp: number;
  difficulty: LessonDifficulty;
  description: string;
  completed: boolean;
  locked: boolean;
  visibilityByRole: UserRole[];
};

const typeMeta: Record<ScheduledLessonDto['type'], { level: LessonLevel; xp: number; difficulty: LessonDifficulty }> =
  {
    grammar: { level: 'B2', xp: 30, difficulty: 'medium' },
    vocabulary: { level: 'B2', xp: 25, difficulty: 'easy' },
    speaking: { level: 'B2', xp: 40, difficulty: 'hard' },
    listening: { level: 'B2', xp: 32, difficulty: 'medium' },
  };

const byLessonKey = new Map<string, ScheduledLessonDto>();
for (const lesson of mockScheduledLessons) {
  const key = lesson.lessonId ?? lesson.id;
  if (!byLessonKey.has(key)) byLessonKey.set(key, lesson);
}

export const mockLessons: MockLesson[] = Array.from(byLessonKey.values()).map((lesson) => {
  const meta = typeMeta[lesson.type];
  return {
    id: lesson.lessonId ?? lesson.id,
    title: lesson.title,
    type: lesson.type,
    level: meta.level,
    duration: lesson.duration,
    xp: meta.xp,
    difficulty: meta.difficulty,
    description: lesson.notes ?? `${lesson.title} lesson`,
    completed: lesson.status === 'completed',
    locked: false,
    visibilityByRole: ['student', 'teacher', 'admin', 'super-admin'],
  };
});

export const getLessonsForAccount = (accountId: string): MockLesson[] =>
  accountId === mockAccounts[0].id ? mockLessons : [];

export function scheduledLessonToCalendarEvent(lesson: ScheduledLessonDto): CalendarEventDto {
  return {
    id: lesson.id,
    title: lesson.title,
    type: lesson.type,
    date: lesson.date,
    time: lesson.startTime,
    duration: lesson.duration,
    teacherId: lesson.teacherId,
    teacherName: lesson.teacherName,
    studentId: lesson.studentId,
    studentName: lesson.studentName,
    status: lesson.status === 'completed' ? 'confirmed' : 'pending',
  };
}

export function calendarEventToScheduledLesson(eventItem: CalendarEventDto): ScheduledLessonDto {
  const [hh, mm] = eventItem.time.split(':').map(Number);
  const endMinutes = hh * 60 + mm + eventItem.duration;
  const endHour = Math.floor(endMinutes / 60);
  const endMin = endMinutes % 60;
  return {
    id: eventItem.id,
    title: eventItem.title,
    type: eventItem.type,
    date: eventItem.date,
    startTime: eventItem.time,
    endTime: `${String(endHour).padStart(2, '0')}:${String(endMin).padStart(2, '0')}`,
    duration: eventItem.duration,
    teacherId: eventItem.teacherId,
    teacherName: eventItem.teacherName,
    studentId: eventItem.studentId,
    studentName: eventItem.studentName,
    status: eventItem.status === 'confirmed' ? 'completed' : 'planned',
    credited: eventItem.status === 'confirmed',
    order: 1,
    recurrence: 'none',
    weeklyDays: [],
  };
}

export const mockCalendarEvents: CalendarEventDto[] = mockScheduledLessons.map(scheduledLessonToCalendarEvent);

export function getStudentScheduledLessons(studentId: string): ScheduledLessonDto[] {
  return mockScheduledLessons.filter((lesson) => lesson.studentId === studentId);
}

export function getStudentCalendarEvents(studentId: string): CalendarEventDto[] {
  return getStudentScheduledLessons(studentId).map(scheduledLessonToCalendarEvent);
}
