import type { ProfileStats } from './achievements';

export type UserRole = 'student' | 'teacher' | 'admin' | 'super-admin';

export type AccountEntity = {
  id: string;
  slug: string;
  name: string;
  status: 'active' | 'inactive';
};

export type UserEntity = {
  id: string;
  accountId: string;
  fullName: string;
  email: string;
  role: UserRole;
  avatarInitials: string;
  targetLevel: string;
  streakDays: number;
};

export type ProfileEntity = {
  id: string;
  accountId: string;
  userId: string;
  telegram: string;
  phone: string;
  timezone: string;
  nativeLanguage: string;
  weeklyGoal: string;
  bio: string;
};

export type ProfileMetaEntity = {
  id: string;
  accountId: string;
  userId: string;
  status: 'active' | 'paused';
  scheduleType: 'fixed' | 'flexible';
  teacherId: string;
  notes: string;
  calendarColor?: string;
};

export type ProfileGoalEntity = {
  id: string;
  accountId: string;
  userId: string;
  text: string;
  done: boolean;
};

export type PracticeActivityEntity = {
  id: string;
  accountId: string;
  href: string;
  title: string;
  description: string;
  icon: string;
  tag: string;
  tagClass: 'tagGreen' | 'tagBlue' | 'tagAmber' | 'tagMuted';
  disabled?: boolean;
};

export type ReviewWordEntity = {
  id: string;
  accountId: string;
  userId: string;
  word: string;
  pos: string;
  def: string;
  status: 'new' | 'learning' | 'known';
};

