import {
  mockAccounts,
  mockUsers as mockUsersEntity,
  type AccountEntity,
  type UserEntity,
  type UserRole,
} from './domains/entities';

export type { UserRole } from './domains/entities';
export type MockUser = UserEntity;
export type SessionRecord = {
  id: string;
  accountId: string;
  userId: string;
  role: UserRole;
};

const rolePreference: UserRole[] = [
  'student',
  'teacher',
  'admin',
  'super-admin',
];

const resolveUserByRole = (role: UserRole): UserEntity | undefined =>
  mockUsersEntity.find((user) => user.role === role);

export const activeRole: UserRole =
  (process.env.NEXT_PUBLIC_MOCK_ROLE as UserRole | undefined) ?? 'admin';

const sessionRows: SessionRecord[] = rolePreference
  .map((role) => {
    const user = resolveUserByRole(role);
    if (!user) return null;
    return {
      id: `session-${role}`,
      accountId: user.accountId,
      userId: user.id,
      role,
    };
  })
  .filter((session): session is SessionRecord => Boolean(session));

export const mockUsersByRole: Record<UserRole, MockUser> =
  rolePreference.reduce(
    (acc, role) => {
      const user = resolveUserByRole(role);
      if (user) acc[role] = user;
      return acc;
    },
    {} as Record<UserRole, MockUser>,
  );

const fallbackUser = mockUsersEntity[0];
const resolvedActiveUser = mockUsersByRole[activeRole] ?? fallbackUser;

export const activeSession: SessionRecord = sessionRows.find(
  (session) => session.userId === resolvedActiveUser.id,
) ?? {
  id: 'session-fallback',
  accountId: resolvedActiveUser.accountId,
  userId: resolvedActiveUser.id,
  role: resolvedActiveUser.role,
};

export const activeAccount: AccountEntity =
  mockAccounts.find((account) => account.id === activeSession.accountId) ??
  mockAccounts[0];
export const activeUser = resolvedActiveUser;
export const activeMockUser = activeUser;
export const mockUsersByAccount = mockUsersEntity.filter(
  (user) => user.accountId === activeAccount.id,
);
export const mockUsers = mockUsersByAccount;
